sp_widget.client_script:
function($scope, spModal, spUtil) {
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------

	var c = this;
	c.options.color = c.options.color.toLowerCase();
	var inputs = JSON.parse(c.options.widget_input);
	inputs.fromModal = true;
	// DFCT0010439 - "My Office" button on Organizational Hierarchy is displaying the wrong table/information
	c.options.table = inputs.table;
	c.options.filter = inputs.filter;
	c.options.view = inputs.view;
	c.image = inputs.image;
	$scope.openModal = function() {
        spModal.open({
            title: c.options.modal_title,
						backdrop:'static',
						widget: c.options.widget_id,
						// DFCT0010439
						table: c.options.table,
						filter: c.options.filter,
						buttons: [
							{
								label: '${Ok}'
							}
						],
						widgetInput: inputs,
						size: (c.options.size === 'Normal') ? '' : c.options.size
        }).then(function(){
					c.server.update();
        });      
    };

		$scope.goToHome = function() {
		window.open('?id=' + $scope.portal.homepage_dv, '_self');	
	}

}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.03.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------
// No updates needed on Tasker theme

.iconlink a label,h2 {
  display: block;
  font-size: 1em;
  font-weight: 300;
  line-height: 1.1;
  padding: 0;
  margin: 0 0 10px 0;
  cursor: pointer;
}

/* TOP ICON ---------- */

a.top_icon {
  display: block;
  padding: 20px;
  text-align: center;
}

a.top_icon .fa {
  display: block;
  text-align: center;
}

/* CIRCLE ICON ---------- */

a.circle_icon {
  display: block;
  padding: 20px 0px 20px 70px;
  position: relative;
}

a.circle_icon .fa {
  position:absolute;
  left: 0px;
  top: 0px;
}

/* COLOR BOX ---------- */

a.color_box {
  display: block;
  position: relative;
  padding: 20px 20px 20px 82px;
  border-radius: 4px;
  margin-bottom: 20px;
}

a.color_box .fa {
  position:absolute;
  left: 20px;
  top: 20px;
  width:42px;
  text-align: center;
}

.icon-link-background-primary {
  background-color: $brand-primary;
}

.icon-link-background-info {
  background-color: $brand-info;
}

.icon-link-background-success {
  background-color: $brand-success;
}

.icon-link-background-warning {
  background-color: $brand-warning;
}

.icon-link-background-danger {
  background-color: $brand-danger;
}

.icon-link-background-default {
  background-color: $brand-primary;
}

.text-primary {
  color: $brand-primary;
  
  &:hover {
    color: darken($brand-primary, 20%);
  }
}

.text-info {
  color: $brand-info;
  
  &:hover {
    color: darken($brand-info, 20%);
  }
}

.text-success {
  color: $brand-success;
  
  &:hover {
    color: darken($brand-success, 20%);
  }
}

.text-warning {
  color: $brand-warning;
  
  &:hover {
    color: darken($brand-warning, 20%);
  }
}

.text-danger {
  color: $brand-danger;
  
  &:hover {
    color: darken($brand-danger, 20%);
  }
}

.text-default {
  color: $brand-primary;
  
  &:hover {
    color: darken($brand-primary, 20%);
  }
}

