//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: Rob Joy
// WIDGET BASE: New widget
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-08-17 | raj | // DFCT0010439 - "My Office" button on Organizational Hierarchy is displaying the wrong table/information
//                                         Change made in Client Script only.
// 2.8 | 2022-03-13 | raj  | STRY0117947 - Org Hierarchy Bifold- Revamp- New Navigation Links in Bifold Header
//                                         Change made in Server Script, Client Controller & HTML
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {

	//  STRY0113883 - reworked code flow
	main();

	function main() {
		// if messages not loaded, load messages
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('discovertasker-widget-in-modal');
		data.messages = taskWidgetIconsAndMessage.loadMessages();
		data.icons = taskWidgetIconsAndMessage.loadIcons();
	}
})($sp, input, data, options, gs);
